<?php declare(strict_types=1); namespace App\Http\Requests\Payroll; use Illuminate\Foundation\Http\FormRequest; class RecordPayrollPaymentRequest extends FormRequest{public function authorize():bool{return $this->user()->can('payroll-payments.create');} public function rules():array{return ['payment_date'=>'required|date','cash_account_id'=>'required|exists:cash_accounts,id','payment_method'=>'required|string','amount'=>'required|integer|min:1','reference_number'=>'nullable|string','notes'=>'nullable|string'];}}
